
import json
import datetime

# Load the JSON data
with open('combined_data.json', 'r') as f:
    data = json.load(f)

# Get the hundred and twenty-first process (index 120)
process = data['processes'][120]

# Populate fields
process['executive_summary'] = "The State Department for Culture and Heritage in Kenya, operating under the Ministry of Sports, Culture and Heritage (or its equivalent), is tasked with the broad mandate of promoting, preserving, and developing Kenya's rich and diverse cultural heritage. Its core responsibilities include advising the government on cultural matters, setting policy standards, fostering national unity through cultural exchange, and supporting cultural industries and infrastructure development, thereby safeguarding national identity and leveraging culture for socio-economic benefit."
process['process_overview']['process_objective'] = "To promote, revitalize, and develop all facets of culture, including performing and visual arts, languages, indigenous health, oral traditions, and the creative industries; to engage in education, information dissemination, and research concerning both tangible and intangible cultural heritage; to coordinate the safeguarding of Kenya's intangible cultural heritage and promote the diversity of cultural expressions; to formulate policies for the sports, culture, and arts industries, and develop national cultural infrastructure; to coordinate all cultural activities nationwide, document national cultural inventories, and support cultural events and festivals; to build capacity for county governments and cultural organizations; to disseminate cultural information and knowledge; to promote the use of Kiswahili, sign language, and other indigenous languages in Kenya; to facilitate cultural exchange programs at local, regional, and international levels; to offer technical support for cultural development initiatives; and to register cultural groups, associations, and agencies to foster their growth and regulation."
process['process_overview']['policy_legal_context'].append("Operating under the Ministry of Sports, Culture and Heritage (or the relevant government ministry responsible for culture, arts, and heritage). Its mandate is rooted in the Constitution of Kenya (Chapter Four, Article 11 on Culture), the Cultural Heritage Act (if applicable, otherwise general heritage acts), and relevant national policies on sports, culture, and arts. The Department plays a crucial role in implementing national cultural development strategies, promoting cultural tourism, and preserving national identity and unity, aligning with national development goals like Vision 2030 for socio-cultural development.")
