process['stakeholders'].append({"stakeholder": "Ministry of Sports, Culture and Heritage", "role": "Parent Ministry providing policy direction, funding, and oversight to the State Department", "responsibilities": "(INFERRED) Formulating cultural policies, allocating resources, strategic guidance for cultural sector."})
